import React from "react";
import { Link } from "react-router-dom";

export default function Navbar() {
  const styles = {
    navbar: {
      display: "flex",
      justifyContent: "space-between",
      alignItems: "center",
      padding: "12px 8%",
      background: "rgba(255, 255, 255, 0.95)",
      boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
      position: "sticky",
      top: 0,
      zIndex: 1000,
      fontFamily: "Poppins, sans-serif",
      backdropFilter: "blur(10px)",
    },
    logo: {
      textDecoration: "none",
      fontSize: "1.7rem",
      fontWeight: 700,
      color: "#ff385c",
      display: "flex",
      alignItems: "center",
      transition: "all 0.3s ease",
    },
    logoEmoji: {
      marginRight: "8px",
      fontSize: "1.9rem",
    },
    navList: {
      listStyle: "none",
      display: "flex",
      alignItems: "center",
      gap: "28px",
      margin: 0,
      padding: 0,
    },
    navItem: {
      textDecoration: "none",
      color: "#333",
      fontSize: "1rem",
      fontWeight: 500,
      position: "relative",
      transition: "color 0.3s ease",
    },
    navItemHover: {
      color: "#ff385c",
    },
    signupBtn: {
      backgroundColor: "#ff385c",
      color: "white",
      padding: "8px 20px",
      borderRadius: "25px",
      fontWeight: 600,
      textDecoration: "none",
      boxShadow: "0 4px 10px rgba(255, 56, 92, 0.3)",
      transition: "all 0.3s ease",
    },
  };

  const handleHover = (e, color) => (e.target.style.color = color);

  return (
    <nav style={styles.navbar}>
      {/* Logo */}
      <div>
        <Link
          to="/"
          style={styles.logo}
          onMouseEnter={(e) => (e.target.style.transform = "scale(1.08)")}
          onMouseLeave={(e) => (e.target.style.transform = "scale(1)")}
        >
          <span style={styles.logoEmoji}>🏡</span> Airbnb
        </Link>
      </div>

      {/* Navigation Links */}
      <ul style={styles.navList}>
        {[
          { to: "/", label: "Home" },
          { to: "/experience", label: "Experience" },
          { to: "/services", label: "Services" },
          { to: "/login", label: "Login" },
        ].map((link) => (
          <li key={link.label}>
            <Link
              to={link.to}
              style={styles.navItem}
              onMouseEnter={(e) => handleHover(e, "#ff385c")}
              onMouseLeave={(e) => handleHover(e, "#333")}
            >
              {link.label}
            </Link>
          </li>
        ))}

        <li>
          <Link
            to="/signup"
            style={styles.signupBtn}
            onMouseEnter={(e) => (e.target.style.backgroundColor = "#e31c5f")}
            onMouseLeave={(e) => (e.target.style.backgroundColor = "#ff385c")}
          >
            Sign Up
          </Link>
        </li>
      </ul>
    </nav>
  );
}
